use strict;
use warnings;
use Fcntl qw(SEEK_SET SEEK_END);
use File::Find;
use File::Basename qw(dirname);

binmode STDOUT, ':raw';

my @zips;
find({
  wanted => sub {
    return if -d $_ && ($_ eq '#snapshot' || $_ eq '#recycle' || $_ =~ /^@/);
    if (-d $_ && ($_ eq '#snapshot' || $_ eq '#recycle' || $_ =~ /^@/)) { $File::Find::prune = 1; return; }
    return unless -f $_;
    return unless $_ =~ /\.zip\z/i;
    push @zips, $File::Find::name;
  },
  no_chdir => 1,
}, '/volume1');

sub zip_entries {
  my ($path) = @_;
  open my $fh, '<:raw', $path or return (undef, "open: $!");
  my $size = -s $fh;
  return ([], undef) if !defined($size) || $size < 22;
  my $tail_len = $size < 66000 ? $size : 66000;
  seek($fh, $size - $tail_len, SEEK_SET) or return (undef, "seek tail: $!");
  read($fh, my $tail, $tail_len) == $tail_len or return (undef, "read tail: $!");
  my $sig = "PK\005\006";
  my $pos = rindex($tail, $sig);
  return (undef, 'no_eocd') if $pos < 0;
  return (undef, 'short_eocd') if $pos + 22 > length($tail);
  my @e = unpack('VvvvvVVv', substr($tail, $pos, 22));
  my ($eocd_sig, $disk, $cd_disk, $disk_entries, $total_entries, $cd_size, $cd_offset, $comment_len) = @e;
  return (undef, 'multi_disk') if $disk != 0 || $cd_disk != 0;
  return (undef, 'zip64_unsupported') if $cd_offset == 0xffffffff || $cd_size == 0xffffffff || $total_entries == 0xffff;
  return (undef, 'bad_cd_bounds') if $cd_offset + $cd_size > $size;
  seek($fh, $cd_offset, SEEK_SET) or return (undef, "seek cd: $!");
  read($fh, my $cd, $cd_size) == $cd_size or return (undef, "read cd: $!");
  my @names;
  my $i = 0;
  while ($i + 46 <= length($cd)) {
    my $h = substr($cd, $i, 46);
    my $s = unpack('V', $h);
    last if $s != 0x02014b50;
    my ($name_len, $extra_len, $comment_len2) = unpack('x28 vvv', $h);
    my $name_start = $i + 46;
    last if $name_start + $name_len > length($cd);
    my $name = substr($cd, $name_start, $name_len);
    push @names, $name;
    $i = $name_start + $name_len + $extra_len + $comment_len2;
  }
  return (\@names, undef);
}

sub clean_entry {
  my ($n) = @_;
  $n =~ s/\\/\//g;
  $n =~ s/^\.\///;
  return undef if $n eq '' || $n =~ /\/$/;
  return undef if $n =~ m{(^|/)\.\.(?:/|$)};
  return undef if $n =~ m{^/};
  return undef if $n =~ m{^__MACOSX/}i;
  return undef if $n =~ m{(^|/)\.DS_Store\z}i;
  return undef if $n =~ m{(^|/)\._[^/]+\z};
  return $n;
}

