  my @roots = ($dir);
  if (opendir my $dh, $dir) {
    my @kids = grep { $_ ne '.' && $_ ne '..' && $_ !~ /^@/ && $_ ne '#snapshot' && $_ ne '#recycle' && -d "$dir/$_" } readdir($dh);
    closedir $dh;
    for my $k (@kids) {
      my $p1 = "$dir/$k";
      push @roots, $p1;
