        my @gkids = grep { $_ ne '.' && $_ ne '..' && $_ !~ /^@/ && $_ ne '#snapshot' && $_ ne '#recycle' && -d "$p1/$_" } readdir($dh2);
        closedir $dh2;
        push @roots, map { "$p1/$_" } @gkids;
      }
    }
  }
  $roots_cache{$dir} = \@roots;
  return @roots;
}

sub sample_entries {
  my (@files) = @_;
  my $n = @files;
  return @files if $n <= 20;
  my @sample;
  for my $i (0..19) {
    my $idx = int($i * ($n - 1) / 19);
