import csv
import os
import sys
import zipfile
from pathlib import Path

ROOT = Path("/mnt/edgesynology1/volume1")
SKIP_NAMES = {"#snapshot", "#recycle"}
MAX_SAMPLE = 30


def should_skip_dir(path: Path) -> bool:
    name = path.name
    return name in SKIP_NAMES or name.startswith("@")


def clean_member(name: str):
    name = name.replace("\\", "/").lstrip("/")
    while name.startswith("./"):
        name = name[2:]
    if not name or name.endswith("/"):
        return None
    parts = [part for part in name.split("/") if part]
    if not parts or any(part == ".." for part in parts):
        return None
    if parts[0].lower() == "__macosx":
        return None
    leaf = parts[-1]
    if leaf.lower() == ".ds_store" or leaf.startswith("._"):
        return None
    return Path(*parts)


def sample_members(members):
    if len(members) <= MAX_SAMPLE:
        return members
    if MAX_SAMPLE <= 1:
        return members[:1]
    last = len(members) - 1
    indexes = sorted({round(i * last / (MAX_SAMPLE - 1)) for i in range(MAX_SAMPLE)})
    return [members[i] for i in indexes]


def candidate_roots(parent: Path):
    roots = [parent]
    try:
        children = [
            child
            for child in parent.iterdir()
            if child.is_dir() and not should_skip_dir(child)
        ]
    except OSError:
        return roots

    roots.extend(children)
    for child in children:
        try:
            roots.extend(
                grandchild
                for grandchild in child.iterdir()
                if grandchild.is_dir() and not should_skip_dir(grandchild)
            )
        except OSError:
            continue
    return roots


def depth_label(parent: Path, root: Path) -> str:
    if root == parent:
        return "same folder"
    depth = len(root.relative_to(parent).parts)
    if depth == 1:
        return "one folder below"
    if depth == 2:
        return "two folders below"
    return f"{depth} folders below"


def find_matches(zip_path: Path, members):
    parent = zip_path.parent
    sample = sample_members(members)
    for root in candidate_roots(parent):
        sample_hits = sum(1 for member in sample if (root / member).exists())
        if sample_hits != len(sample):
            continue

        full_hits = sum(1 for member in members if (root / member).exists())
        if full_hits == len(members):
            yield {
                "match_type": depth_label(parent, root),
                "zip_path": str(zip_path),
                "extraction_root": str(root),
                "matched_files": full_hits,
                "member_files": len(members),
                "first_member": str(members[0]),
                "error": "",
            }


def iter_zip_paths():
    for dirpath, dirnames, filenames in os.walk(ROOT):
        dirnames[:] = [
            dirname
            for dirname in dirnames
            if dirname not in SKIP_NAMES and not dirname.startswith("@")
        ]
        for filename in filenames:
            if filename.lower().endswith(".zip"):
                yield Path(dirpath) / filename


def main():
    writer = csv.DictWriter(
        sys.stdout,
        fieldnames=[
            "match_type",
            "zip_path",
            "extraction_root",
            "matched_files",
            "member_files",
            "first_member",
            "error",
        ],
        delimiter="\t",
        lineterminator="\n",
    )
    writer.writeheader()

    zip_count = 0
    parsed = 0
    errors = 0
    matches = 0

    for zip_path in iter_zip_paths():
        zip_count += 1
        if zip_count % 1000 == 0:
            print(f"progress zip_count={zip_count}", file=sys.stderr, flush=True)

        try:
            with zipfile.ZipFile(zip_path) as archive:
                members = [
                    cleaned
                    for cleaned in (clean_member(info.filename) for info in archive.infolist())
                    if cleaned is not None
                ]
        except Exception as exc:
            errors += 1
            writer.writerow(
                {
                    "match_type": "ZIP_READ_ERROR",
                    "zip_path": str(zip_path),
                    "extraction_root": "",
                    "matched_files": "",
                    "member_files": "",
                    "first_member": "",
                    "error": repr(exc),
                }
            )
            continue

        parsed += 1
        if not members:
            continue

        for row in find_matches(zip_path, members):
            matches += 1
            writer.writerow(row)

    print(
        f"SUMMARY\tzip_count={zip_count}\tparsed={parsed}\terrors={errors}\tmatches={matches}",
        file=sys.stderr,
    )


if __name__ == "__main__":
    main()

